import{_ as t,c as o,o as r,a1 as a}from"./chunks/framework.DDNAyvCW.js";const s="/assets/host_create_p.D5tvuf_k.png",u=JSON.parse('{"title":"Add a Personal Host","description":"","frontmatter":{},"headers":[],"relativePath":"docs/hosts/add-personal.md","filePath":"docs/hosts/add-personal.md"}'),n={name:"docs/hosts/add-personal.md"};function i(d,e,l,h,c,g){return r(),o("div",null,e[0]||(e[0]=[a('<h1 id="add-a-personal-host" tabindex="-1">Add a Personal Host <a class="header-anchor" href="#add-a-personal-host" aria-label="Permalink to &quot;Add a Personal Host&quot;">​</a></h1><p>Add a personal server to Chaterm so you can connect to it via SSH directly from the workspace.</p><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><p>Before adding a personal host, make sure you have the following ready:</p><ul><li><strong>Chaterm installed</strong> and running on your machine. See <a href="/docs/start/downloads/">Downloads</a> if you have not installed it yet.</li><li><strong>SSH credentials</strong> for the target server -- either a password or an SSH private key.</li><li><strong>Server IP address</strong> (or hostname) and the SSH port number (default <code>22</code>).</li></ul><h2 id="steps" tabindex="-1">Steps <a class="header-anchor" href="#steps" aria-label="Permalink to &quot;Steps&quot;">​</a></h2><p><img src="'+s+'" alt=""></p><ol><li>Open the <strong>Host Management</strong> page from the left sidebar.</li><li>Click <strong>Add Host</strong> in the top-right corner of the Host Management page.</li><li>In the <strong>Add Host</strong> sidebar that opens, set <strong>Device type</strong> to <strong>Server / Personal</strong>.</li><li>Fill in the remaining configuration fields described in the table below.</li><li>Click <strong>Create</strong> to save the host.</li></ol><h2 id="configuration-fields" tabindex="-1">Configuration Fields <a class="header-anchor" href="#configuration-fields" aria-label="Permalink to &quot;Configuration Fields&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Field</th><th>Description</th><th>Required</th></tr></thead><tbody><tr><td><strong>Device type</strong></td><td>Select <strong>Server / Personal</strong> to indicate this is a personal server.</td><td>Yes</td></tr><tr><td><strong>Connection IP/Address</strong></td><td>The IP address or hostname of the target server (e.g. <code>192.168.1.100</code> or <code>dev.example.com</code>).</td><td>Yes</td></tr><tr><td><strong>Port</strong></td><td>The SSH service port on the target server. Defaults to <code>22</code>. Change this only if your server uses a non-standard port.</td><td>Yes</td></tr><tr><td><strong>Username</strong></td><td>The SSH login username (e.g. <code>root</code>, <code>ubuntu</code>, <code>deploy</code>).</td><td>Yes</td></tr><tr><td><strong>Authentication method</strong></td><td>Choose <strong>Password</strong> or <strong>SSH Key</strong>. See the tip below for guidance.</td><td>Yes</td></tr><tr><td><strong>SSH proxy</strong></td><td>If the server is behind a firewall or NAT, configure an SSH proxy to route the connection through an intermediate server. Leave empty for direct connections.</td><td>No</td></tr><tr><td><strong>Alias</strong></td><td>A friendly display name so you can quickly identify this host in the host list (e.g. <code>Dev API Server</code>).</td><td>Yes</td></tr><tr><td><strong>Group</strong></td><td>Assign the host to a group for easier organization (e.g. <code>development</code>, <code>production</code>). You can select an existing group or type a new group name.</td><td>No</td></tr></tbody></table><h2 id="authentication-methods" tabindex="-1">Authentication Methods <a class="header-anchor" href="#authentication-methods" aria-label="Permalink to &quot;Authentication Methods&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">Choosing an authentication method</p><ul><li><strong>Password authentication</strong> is the simplest option. Enter the SSH password for the specified username.</li><li><strong>Key authentication</strong> is more secure and recommended for production servers. Select an SSH key that has already been imported in <a href="/docs/manage/keys/">Key Management</a>, or click the link to add a new key first and then return here to select it.</li></ul></div><h2 id="what-happens-next" tabindex="-1">What Happens Next <a class="header-anchor" href="#what-happens-next" aria-label="Permalink to &quot;What Happens Next&quot;">​</a></h2><p>After you click <strong>Create</strong>, the new host appears in your host list on the Host Management page. From here you can:</p><ul><li><strong>Connect immediately</strong> -- click the host entry to open an SSH terminal session. See <a href="/docs/hosts/connect">Connect to a Host</a> for details on the terminal features available during a session.</li><li><strong>Edit or organize</strong> -- right-click the host to rename, clone, move to a different group, or delete it. See <a href="/docs/hosts/edit-clone-delete">Edit, Clone &amp; Delete</a> for more information.</li><li><strong>Manage SSH keys</strong> -- if you need to rotate or add keys later, visit <a href="/docs/manage/keys/">Key Management</a>.</li></ul>',15)]))}const m=t(n,[["render",i]]);export{u as __pageData,m as default};
